INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('aboriginal-6f0ba476-moex-00260', 'aboriginal-6f0ba476', 'aboriginal-6f0ba476-moex-112-9b7ab1bb', 'sub-aboriginal-6f0ba476-02', NULL, 'single_choice', '下列何者屬於附停止條件之處分行為？', '["甲以分期付款方式，向乙購買冷氣機，約定甲付清所有價金時，始取得冷氣機之所有權", "甲以分期付款方式，向乙購買缺貨之冷氣機，約定乙取得貨源時，甲開始付款", "甲乙約定，若乙於1年內赴日旅遊，甲將贈乙日幣10萬元", "甲乙約定，若乙未於1年內赴美深造，乙應返還向甲借用之電腦"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:54+00:00", "source_pdf_sha1": "24a86a5609a7", "answer_pdf_sha1": "239ddc873623", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "508", "s": "0801", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('aboriginal-6f0ba476-moex-00261', 'aboriginal-6f0ba476', 'aboriginal-6f0ba476-moex-112-9b7ab1bb', 'sub-aboriginal-6f0ba476-02', NULL, 'single_choice', '甲贈與乙咖啡杯盤1組，下列敘述何者正確？', '["甲將咖啡杯盤移轉於乙後，仍得任意撤銷對乙之贈與", "咖啡杯盤若因甲之輕過失而滅失，則屬於可歸責於甲之事由致給付不能", "若甲給付遲延，乙不得請求遲延之損害賠償", "凡因贈與物之瑕疵導致受贈人乙受損害者，甲皆須對乙負擔損害賠償責任"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:54+00:00", "source_pdf_sha1": "24a86a5609a7", "answer_pdf_sha1": "239ddc873623", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "508", "s": "0801", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('aboriginal-6f0ba476-moex-00262', 'aboriginal-6f0ba476', 'aboriginal-6f0ba476-moex-112-9b7ab1bb', 'sub-aboriginal-6f0ba476-02', NULL, 'single_choice', '下列關於動產所有權善意取得之敘述，何者錯誤？', '["以動產所有權移轉之無權處分為要件", "以受讓人於受讓時不知讓與人無權處分一事，且就其不知無重大過失為要件", "善意受讓人若欲取得動產所有權，須支付相當之價金給真正動產所有人", "真正動產所有人，請求善意受讓人返還動產，無理由"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:54+00:00", "source_pdf_sha1": "24a86a5609a7", "answer_pdf_sha1": "239ddc873623", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "508", "s": "0801", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 15, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('aboriginal-6f0ba476-moex-00263', 'aboriginal-6f0ba476', 'aboriginal-6f0ba476-moex-112-9b7ab1bb', 'sub-aboriginal-6f0ba476-02', NULL, 'single_choice', '區分地上權人與其設定之土地上下有使用、收益權利之人，約定相互間使用收益之限制者，下列 關於該約定之敘述，何者正確？', '["該項約定應經土地所有人同意，始生效力", "該項約定應經土地所有人同意，並辦理登記，始生效力", "該項約定無須土地所有人同意，但非經登記，不得對抗第三人", "該項約定無須土地所有人同意，但應辦理登記，始生效力"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:54+00:00", "source_pdf_sha1": "24a86a5609a7", "answer_pdf_sha1": "239ddc873623", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "508", "s": "0801", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 16, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('aboriginal-6f0ba476-moex-00264', 'aboriginal-6f0ba476', 'aboriginal-6f0ba476-moex-112-9b7ab1bb', 'sub-aboriginal-6f0ba476-02', NULL, 'single_choice', '下列關於共有物分割行為之敘述，何者錯誤？', '["共有人部分相同之數不動產，限於相鄰之不動產始得請求合併分割，若共有人相同之數不動產， 則無此限制", "共有不動產之應有部分上設有普通抵押權者，於共有物分割時，該抵押權當然移存於抵押人所 分得之部分", "共有物分割之效力，係向後發生而非溯及既往，故共有人自共有物分割之效力發生時起，始取 得分得部分之所有權", "共有人原則上得隨時請求分割共有物，但公同共有人於公同關係存續中，不得請求分割其公同 共有物"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:54+00:00", "source_pdf_sha1": "24a86a5609a7", "answer_pdf_sha1": "239ddc873623", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "508", "s": "0801", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 17, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('aboriginal-6f0ba476-moex-00265', 'aboriginal-6f0ba476', 'aboriginal-6f0ba476-moex-112-9b7ab1bb', 'sub-aboriginal-6f0ba476-02', NULL, 'single_choice', '下列關於添附之敘述，何者正確？', '["在他人土地上建築房屋，土地所有人得主張因附合而取得該房屋之所有權", "加工於他人之不動產者，其加工物之所有權，原則上屬於材料所有人", "動產因附合而為不動產之重要成分者，若該不動產上原有抵押權，該抵押權效力及於附合物", "因添附之規定而權利受損害者，得依無因管理之規定，請求償還價額"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:54+00:00", "source_pdf_sha1": "24a86a5609a7", "answer_pdf_sha1": "239ddc873623", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "508", "s": "0801", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 18, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('aboriginal-6f0ba476-moex-00266', 'aboriginal-6f0ba476', 'aboriginal-6f0ba476-moex-112-9b7ab1bb', 'sub-aboriginal-6f0ba476-02', NULL, 'single_choice', '甲生前繼續受乙扶養，乙死後有遺產新臺幣（下同）1,000萬元，由乙之繼承人丙繼承。下列敘述 何者錯誤？', '["如果乙有遺囑遺贈甲200萬元，甲得請求丙為給付", "如果乙之遺囑並無遺贈甲，甲就遺產無受酌給權利", "親屬會議決議不酌給甲遺產，甲得向法院聲訴", "親屬會議已開而就酌給甲遺產與否未為決議，甲得聲請法院處理"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:54+00:00", "source_pdf_sha1": "24a86a5609a7", "answer_pdf_sha1": "239ddc873623", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "508", "s": "0801", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 19, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('aboriginal-6f0ba476-moex-00267', 'aboriginal-6f0ba476', 'aboriginal-6f0ba476-moex-112-9b7ab1bb', 'sub-aboriginal-6f0ba476-02', NULL, 'single_choice', '下列何種行為非經登記，不生物權變動之效力？', '["不動產物權因混同而消滅者", "抵押權隨同債權而讓與受讓人者", "不動產物權因拋棄而消滅者", "因繼承而取得被繼承人之不動產者"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:54+00:00", "source_pdf_sha1": "24a86a5609a7", "answer_pdf_sha1": "239ddc873623", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "508", "s": "0801", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 20, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('aboriginal-6f0ba476-moex-00268', 'aboriginal-6f0ba476', 'aboriginal-6f0ba476-moex-112-9b7ab1bb', 'sub-aboriginal-6f0ba476-02', NULL, 'single_choice', '甲男乙女為夫妻，未約定夫妻財產制。甲婚前有價值新臺幣（下同）1,000萬元之A屋一棟。婚 後，甲以其營業所得購置B地價值2,000萬元，但負有債務1,100萬元。乙婚後繼承價值1,000萬 元之C屋。甲將A屋賣掉償還1,000萬元債務，其餘100萬元債務，乙以C屋之租賃所得代為清 償。甲乙兩願離婚時，甲除價值2,000萬元之B地外，別無其他財產。乙除C屋外，尚有C屋之 租賃所得200萬元。乙得向甲請求多少金額之剩餘財產分配？', '["500萬元", "400萬元", "300萬元", "200萬元"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:54+00:00", "source_pdf_sha1": "24a86a5609a7", "answer_pdf_sha1": "239ddc873623", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "508", "s": "0801", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 21, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('aboriginal-6f0ba476-moex-00269', 'aboriginal-6f0ba476', 'aboriginal-6f0ba476-moex-112-9b7ab1bb', 'sub-aboriginal-6f0ba476-02', NULL, 'single_choice', '甲與乙於民國（下同）110年10月1日兩願離婚登記後，甲與丙於111年3月2日結婚。乙對離 婚後悔，訴請確認離婚無效，於112年4月1日獲勝訴判決確定。下列敘述何者正確？', '["若甲乙婚姻視為消滅，因甲乙均無過失，故不得請求財產分配", "不論任何情況下，甲丙婚姻均因重婚而為無效", "與甲結婚時，丙係善意且無過失信賴甲乙婚姻消滅之兩願離婚登記，甲丙婚姻即為有效", "若甲乙婚姻視為消滅，其效力應至111年3月1日為止"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:54+00:00", "source_pdf_sha1": "24a86a5609a7", "answer_pdf_sha1": "239ddc873623", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "508", "s": "0801", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 22, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "財稅行政"}'::jsonb, NULL)
